import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"66. Excessive Leave Accrual","description":"","frontmatter":{"title":"66. Excessive Leave Accrual","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","annual-leave","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/leave/66-excessive-leave-accrual.md","filePath":"ebas/has-managers-admin/common-terms/leave/66-excessive-leave-accrual.md"}'),r={name:"ebas/has-managers-admin/common-terms/leave/66-excessive-leave-accrual.md"};function s(i,e,l,p,c,h){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_66-excessive-leave-accrual" tabindex="-1">66. Excessive Leave Accrual <a class="header-anchor" href="#_66-excessive-leave-accrual" aria-label="Permalink to &quot;66. Excessive Leave Accrual&quot;">​</a></h1><p><strong>66.1</strong> General Provisions</p><p><strong>(a)</strong> This clause contains provisions, additional to the NES and <a href="/eba/ebas/has-managers-admin/common-terms/leave/53-annual-leave.html">clause 53</a> of Section 1 (Annual Leave), that deal with the taking of paid annual</p><p>leave as a way of dealing with the accrual of excessive paid annual leave.</p><p><strong>(b)</strong> An Employee is deemed to have excessive leave accrual where the Employee has a</p><p><strong>(i)</strong> more than 8 weeks’ paid annual leave; or</p><p><strong>(ii)</strong> more than 10 weeks’ paid annual leave for Employees who are entitled to the Additional Week’s Annual Leave at sub- <a href="/eba/ebas/has-managers-admin/common-terms/leave/53-annual-leave.html">clause 53.4</a> of Section 1.</p><p><strong>(c)</strong> If an Employee has an excessive leave accrual, the Employer or the Employee may seek to confer with the other and genuinely try to reach agreement on how to reduce or eliminate the excessive leave accrual</p><p><strong>66.2</strong> Direction to take Annual Leave</p><p><strong>(a)</strong> Where agreement cannot be reached in accordance with 66.1(c), the Employer may direct the Employee to take some of that accrued annual leave provided that:</p><p><strong>(i)</strong> the Employee has first been given a reasonable opportunity to submit a plan to reduce the leave to not less than six weeks within six months, subject to 66.2(ii) below;</p><p><strong>(ii)</strong> the direction does not require the Employee to take a period of annual leave beginning less than 8 weeks, or more than 12 months, after the direction is given;</p><p><strong>(iii)</strong> the Employer will not unreasonably refuse to agree to a leave reduction plan which includes saving leave for an extended vacation within 18 months of the date of agreement to the leave reduction plan. The agreement is to be in writing and signed by both the Employer and the Employee;</p><p><strong>(iv)</strong> in directing that the Employee take leave the Employee cannot be directed to reduce the accrued leave to less than six weeks;</p><p><strong>(v)</strong> the period of annual leave is no less than one week; and</p><p><strong>(vi)</strong> the direction is not inconsistent with any leave arrangement agreed by the Employer and Employee.</p><p><strong>66.3</strong> Excessive leave accruals: request by employee for leave</p><p><strong>(a)</strong> Where agreement cannot be reached in accordance with 66.1(c), the Employee may give a written notice to the Employer requesting to take one or more periods of annual leave.</p><p><strong>(b)</strong> However, an Employee may only give a notice to the Employer under clause 66.3(a) if:</p><p><strong>(i)</strong> the Employee has had an excessive leave accrual, as deemed by subclause 66.1(b), for more than 6 months at the time of giving the notice; and</p><p><strong>(ii)</strong> the Employee has not been given a direction under clause</p><p><strong>63.2</strong> that, when any other paid annual leave arrangements are taken into account, would eliminate the Employee’s excessive leave accrual.</p><p><strong>(c)</strong> A notice given by an Employee under clause 66.3(a) must not:</p><p><strong>(i)</strong> if granted, reduce the Employee’s accrued leave to less than six weeks; or</p><p><strong>(ii)</strong> provide for the Employee to take any period of paid annual leave of less than one week; or</p><p><strong>(iii)</strong> provide for the Employee to take a period of paid annual leave beginning less than 8 weeks, or more than 12 months, after the notice is given; or</p><p><strong>(iv)</strong> be with any leave arrangement agreed by the employer and the employee.</p><p><strong>(d)</strong> An employee is not entitled to request by a notice under clause 66.3(a) more than 4 weeks’ paid annual leave (or 5 weeks’ paid annual leave for a weekend worker) in any period of 12 months.</p><p><strong>66.4</strong> Disputes regarding excess annual leave Without limiting the Dispute Resolution Procedure of the Agreement, either an Employee or Employer (or their representative/s) may refer a dispute about the following matters to the Commission:</p><p><strong>(a)</strong> a dispute about whether the Employer or employee has requested a meeting and genuinely tried to reach agreement;</p><p><strong>(b)</strong> a dispute about whether the Employer has unreasonable refused to agree to a request by the employee to take paid annual leave; and</p><p><strong>(c)</strong> a dispute about whether a direction to take leave complies with the clause.</p>',32)])])}const g=a(r,[["render",s]]);export{d as __pageData,g as default};
